migrations.m0002:
-- Allow saving both directions (front/back vs back/front) and multiple variants.
-- Old rule: unique(course_id, front_nine_id, back_nine_id)
-- New rule: unique(course_id, name)

DROP INDEX IF EXISTS `course_combos_course_id_front_back_uq`;
CREATE UNIQUE INDEX `course_combos_course_id_name_uq` ON `course_combos` (`course_id`,`name`);

migrations.m0003:
-- Store which tee was played for a round.

ALTER TABLE `rounds` ADD `tee_id` text REFERENCES course_tees(id);
CREATE INDEX `rounds_tee_id_idx` ON `rounds` (`tee_id`);

migrations.m0004:
-- Mark a round as abandoned/cancelled without deleting it.

ALTER TABLE `rounds` ADD `abandoned_at` text;
CREATE INDEX `rounds_abandoned_at_idx` ON `rounds` (`abandoned_at`);

migrations.m0005:
-- Store a stock image key for course cards.

ALTER TABLE `courses` ADD `image_key` text;
CREATE INDEX `courses_image_key_idx` ON `courses` (`image_key`);

